21	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
22	  const results = scenario.steps.map((step) => {
23	    const policyBase = step.items.reduce(
24	      (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
25	      0,
26	    );
27	    const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
28	    const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
29	    return { premium };
30	  });
31	  return { results };
32	};
